// Barrel for the auto-generated Soroban contract bindings.
//
// Each contract module exports overlapping symbol names (`Client`, `Errors`,
// `DataKey`, ...), so they are re-exported under per-contract namespaces to
// avoid collisions. Import them like:
//
//   import { InvoiceContract, CreditScoreContract } from '@/src/generated';
//   const client = new InvoiceContract.Client({ ... });
//
// These files are generated by `stellar contract bindings typescript` and must
// not be edited by hand. Regenerate with `./scripts/gen-bindings.sh`
// (see CONTRIBUTING.md → "Regenerating contract bindings").

export * as InvoiceContract from './invoice';
export * as CreditScoreContract from './credit_score';

// NOTE: pool bindings are intentionally not generated yet. The pool contract
// currently fails to compile because its `PoolError` enum exceeds Soroban's
// 50-case limit for contract-spec error enums, so no WASM/spec can be produced.
// `./scripts/gen-bindings.sh` and the CI bindings job already include `pool`;
// uncomment the line below once the contract build is fixed.
// export * as PoolContract from './pool';
